diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index fdadf729fbd5..c76a3b5dc956 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7765,6 +7765,71 @@ static Instruction *foldFCmpReciprocalAndZero(FCmpInst &I, Instruction *LHSI,
   return new FCmpInst(Pred, LHSI->getOperand(1), RHSC, "", &I);
 }

+/// Optimize select patterns computing fabs(X) compared with zero.
+/// For select (fcmp oge X, 0), X, fneg X (fabs), fcmp oeq/une with 0 can be
+/// simplified because fabs(X) == 0 iff X == 0.
+static Instruction *foldSelectFAbsWithFcmpZero(FCmpInst &I, InstCombinerImpl &IC) {
+  auto *SI = dyn_cast<SelectInst>(I.getOperand(0));
+  if (!SI)
+    return nullptr;
+  
+  Value *Cond = SI->getCondition();
+  Value *TrueVal = SI->getTrueValue();
+  Value *FalseVal = SI->getFalseValue();
+  
+  // Try to match: select (fcmp Pred X, 0), X, fneg X  OR  select (fcmp Pred X, 0), fneg X, X
+  FCmpInst::Predicate CondPred;
+  Value *X;
+  if (!match(Cond, m_FCmp(CondPred, m_Value(X), m_AnyZeroFP())))
+    return nullptr;
+  
+  // Check if the select pattern computes fabs or a similar pattern
+  // For equality comparisons (oeq, one, ueq, une), the result is 0 iff X is 0
+  // regardless of the condition predicate
+  bool IsFAbs = false;
+  
+  // Pattern: (Pred X, 0) ? X : -X  (fabs when Pred is oge or ogt)
+  if (TrueVal == X && match(FalseVal, m_FNeg(m_Specific(X)))) {
+    if (CondPred == FCmpInst::FCMP_OGE || CondPred == FCmpInst::FCMP_OGT ||
+        CondPred == FCmpInst::FCMP_OEQ || CondPred == FCmpInst::FCMP_ONE ||
+        CondPred == FCmpInst::FCMP_UEQ || CondPred == FCmpInst::FCMP_UNE)
+      IsFAbs = true;
+  }
+  // Pattern: (Pred X, 0) ? -X : X  (fabs when Pred is olt or ole)
+  else if (match(TrueVal, m_FNeg(m_Specific(X))) && FalseVal == X) {
+    if (CondPred == FCmpInst::FCMP_OLT || CondPred == FCmpInst::FCMP_OLE ||
+        CondPred == FCmpInst::FCMP_OEQ || CondPred == FCmpInst::FCMP_ONE ||
+        CondPred == FCmpInst::FCMP_UEQ || CondPred == FCmpInst::FCMP_UNE)
+      IsFAbs = true;
+  }
+  
+  if (!IsFAbs)
+    return nullptr;
+  
+  const APFloat *C;
+  if (!match(I.getOperand(1), m_APFloat(C)))
+    return nullptr;
+  
+  // Only handle equality comparisons with 0 for now
+  // fabs(X) == 0  -->  X == 0
+  // fabs(X) != 0  -->  X != 0
+  if (!C->isZero())
+    return nullptr;
+  
+  FCmpInst::Predicate Pred = I.getPredicate();
+  if (Pred != FCmpInst::FCMP_OEQ && Pred != FCmpInst::FCMP_UEQ &&
+      Pred != FCmpInst::FCMP_ONE && Pred != FCmpInst::FCMP_UNE)
+    return nullptr;
+  
+  // For these predicates, fabs(X) pred 0 is equivalent to X pred 0
+  auto replacePredAndOp0 = [&IC](FCmpInst *I, FCmpInst::Predicate P, Value *X) {
+    I->setPredicate(P);
+    return IC.replaceOperand(*I, 0, X);
+  };
+  
+  return replacePredAndOp0(&I, Pred, X);
+}
+
 /// Optimize fabs(X) compared with zero.
 static Instruction *foldFabsWithFcmpZero(FCmpInst &I, InstCombinerImpl &IC) {
   Value *X;
@@ -8071,6 +8136,9 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
   if (Instruction *R = foldFabsWithFcmpZero(I, *this))
     return R;

+  if (Instruction *R = foldSelectFAbsWithFcmpZero(I, *this))
+    return R;
+
   if (match(Op0, m_FNeg(m_Value(X)))) {
     // fcmp pred (fneg X), C --> fcmp swap(pred) X, -C
     Constant *C;

