  7964 | Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
  7965 |   bool Changed = false;
  7966 | 
  7967 |   /// Orders the operands of the compare so that they are listed from most
  7968 |   /// complex to least complex.  This puts constants before unary operators,
  7969 |   /// before binary operators.
  7970 |   if (getComplexity(I.getOperand(0)) < getComplexity(I.getOperand(1))) {
  7971 |     I.swapOperands();
  7972 |     Changed = true;
  7973 |   }
  7974 | 
  7975 |   const CmpInst::Predicate Pred = I.getPredicate();
  7976 |   Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1);
  7977 |   if (Value *V = simplifyFCmpInst(Pred, Op0, Op1, I.getFastMathFlags(),
  7978 |                                   SQ.getWithInstruction(&I)))
  7979 |     return replaceInstUsesWith(I, V);
  7980 | 
  7981 |   // Simplify 'fcmp pred X, X'
  7982 |   Type *OpType = Op0->getType();
  7983 |   assert(OpType == Op1->getType() && "fcmp with different-typed operands?");
  7984 |   if (Op0 == Op1) {
  7985 |     switch (Pred) {
  7986 |       default: break;
  7987 |     case FCmpInst::FCMP_UNO:    // True if unordered: isnan(X) | isnan(Y)
  7988 |     case FCmpInst::FCMP_ULT:    // True if unordered or less than
  7989 |     case FCmpInst::FCMP_UGT:    // True if unordered or greater than
  7990 |     case FCmpInst::FCMP_UNE:    // True if unordered or not equal
  7991 |       // Canonicalize these to be 'fcmp uno %X, 0.0'.
  7992 |       I.setPredicate(FCmpInst::FCMP_UNO);
  7993 |       I.setOperand(1, Constant::getNullValue(OpType));
  7994 |       return &I;
  7995 | 
  7996 |     case FCmpInst::FCMP_ORD:    // True if ordered (no nans)
  7997 |     case FCmpInst::FCMP_OEQ:    // True if ordered and equal
  7998 |     case FCmpInst::FCMP_OGE:    // True if ordered and greater than or equal
  7999 |     case FCmpInst::FCMP_OLE:    // True if ordered and less than or equal
  8000 |       // Canonicalize these to be 'fcmp ord %X, 0.0'.
  8001 |       I.setPredicate(FCmpInst::FCMP_ORD);
  8002 |       I.setOperand(1, Constant::getNullValue(OpType));
  8003 |       return &I;
  8004 |     }
  8005 |   }
  8006 | 
  8007 |   if (I.isCommutative()) {
  8008 |     if (auto Pair = matchSymmetricPair(I.getOperand(0), I.getOperand(1))) {
  8009 |       replaceOperand(I, 0, Pair->first);
  8010 |       replaceOperand(I, 1, Pair->second);
  8011 |       return &I;
  8012 |     }
  8013 |   }
  8014 | 
  8015 |   // If we're just checking for a NaN (ORD/UNO) and have a non-NaN operand,
  8016 |   // then canonicalize the operand to 0.0.
  8017 |   if (Pred == CmpInst::FCMP_ORD || Pred == CmpInst::FCMP_UNO) {
  8018 |     if (!match(Op0, m_PosZeroFP()) &&
  8019 |         isKnownNeverNaN(Op0, 0, getSimplifyQuery().getWithInstruction(&I)))
  8020 |       return replaceOperand(I, 0, ConstantFP::getZero(OpType));
  8021 | 
  8022 |     if (!match(Op1, m_PosZeroFP()) &&
  8023 |         isKnownNeverNaN(Op1, 0, getSimplifyQuery().getWithInstruction(&I)))
  8024 |       return replaceOperand(I, 1, ConstantFP::getZero(OpType));
  8025 |   }
  8026 | 
  8027 |   // fcmp pred (fneg X), (fneg Y) -> fcmp swap(pred) X, Y
  8028 |   Value *X, *Y;
  8029 |   if (match(Op0, m_FNeg(m_Value(X))) && match(Op1, m_FNeg(m_Value(Y))))
  8030 |     return new FCmpInst(I.getSwappedPredicate(), X, Y, "", &I);
  8031 | 
  8032 |   if (Instruction *R = foldFCmpFNegCommonOp(I))
  8033 |     return R;
  8034 | 
  8035 |   // Test if the FCmpInst instruction is used exclusively by a select as
  8036 |   // part of a minimum or maximum operation. If so, refrain from doing
  8037 |   // any other folding. This helps out other analyses which understand
  8038 |   // non-obfuscated minimum and maximum idioms, such as ScalarEvolution
  8039 |   // and CodeGen. And in this case, at least one of the comparison
  8040 |   // operands has at least one user besides the compare (the select),
  8041 |   // which would often largely negate the benefit of folding anyway.
  8042 |   if (I.hasOneUse())
