  8069 |   // fcmp ule X, -inf -> fcmp ueq X, -inf
  8070 |   // fcmp ugt X, -inf -> fcmp une X, -inf
  8071 |   // fcmp uge X, -inf -> true
  8072 |   const APFloat *C;
  8073 |   if (match(Op1, m_APFloat(C)) && C->isInfinity()) {
  8074 |     switch (C->isNegative() ? FCmpInst::getSwappedPredicate(Pred) : Pred) {
  8075 |     default:
  8076 |       break;
  8077 |     case FCmpInst::FCMP_ORD:
  8078 |     case FCmpInst::FCMP_UNO:
  8079 |     case FCmpInst::FCMP_TRUE:
  8080 |     case FCmpInst::FCMP_FALSE:
  8081 |     case FCmpInst::FCMP_OGT:
  8082 |     case FCmpInst::FCMP_ULE:
