  8086 |     case FCmpInst::FCMP_OLE:
  8087 |       return new FCmpInst(FCmpInst::FCMP_ORD, Op0, ConstantFP::getZero(OpType),
  8088 |                           "", &I);
  8089 |     case FCmpInst::FCMP_OGE:
  8090 |       return new FCmpInst(FCmpInst::FCMP_OEQ, Op0, Op1, "", &I);
  8091 |     case FCmpInst::FCMP_ULT:
  8092 |       return new FCmpInst(FCmpInst::FCMP_UNE, Op0, Op1, "", &I);
  8093 |     case FCmpInst::FCMP_UGT:
  8094 |       return new FCmpInst(FCmpInst::FCMP_UNO, Op0, ConstantFP::getZero(OpType),
  8095 |                           "", &I);
  8096 |     case FCmpInst::FCMP_UGE:
